  it("returns the minimum when value is below the range", () => {
    expect(clamp(1, 3, 10)).toBe(3);
  });

  it("returns the maximum when value is above the range", () => {
    expect(clamp(12, 3, 10)).toBe(10);
  });

  it("returns the original value when it is inside the range", () => {
    expect(clamp(7, 3, 10)).toBe(7);
